content:
{
  "sentences": [
    {
      "text": "昨天發生了一件糟糕的事情，我的手機壞掉了。",
      "pinyin": "Zuótiān fāshēng le yī jiàn zāogāo de shìqíng, wǒ de shǒujī huài diào le.",
      "pinyin_numeric": "zuo2tian1 fa1sheng1 le5 yi1 jian4 zao1gao1 de5 shi4qing2, wo3 de5 shou3ji1 huai4 diao4 le5.",
      "translation_en": "A terrible thing happened yesterday—my phone broke.",
      "translation_ko": "어제 끔찍한 일이 생겼어요. 제 휴대폰이 고장 났어요."
    },
    {
      "text": "因為塞車，所以我今天上班遲到了。",
      "pinyin": "Yīnwèi sāichē, suǒyǐ wǒ jīntiān shàngbān chídào le.",
      "pinyin_numeric": "yin1wei4 sai1che1, suo3yi3 wo3 jin1tian1 shang4ban1 chi2dao4 le5.",
      "translation_en": "Because of traffic, I was late for work today.",
      "translation_ko": "교통 체증 때문에 오늘 출근에 지각했어요."
    },
    {
      "text": "他忘記帶鑰匙，結果進不了家門。",
      "pinyin": "Tā wàngjì dài yàoshi, jiéguǒ jìn bù liǎo jiāmén.",
      "pinyin_numeric": "ta1 wang4ji4 dai4 yao4shi5, jie2guo3 jin4 bu4 liao3 jia1men2.",
      "translation_en": "He forgot to bring his keys, so he couldn't get into the house.",
      "translation_ko": "그가 열쇠를 가져오는 걸 잊어버려서 집에 들어갈 수 없었어요."
    },
    {
      "text": "昨天突然下大雨，我沒有帶傘，所以全身都濕了。",
      "pinyin": "Zuótiān tūrán xià dàyǔ, wǒ méiyǒu dài sǎn, suǒyǐ quánshēn dōu shī le.",
      "pinyin_numeric": "zuo2tian1 tu1ran2 xia4 da4yu3, wo3 mei2you3 dai4 san3, suo3yi3 quan2shen1 dou1 shi1 le5.",
      "translation_en": "It suddenly rained heavily yesterday, and I didn't bring an umbrella, so I got completely soaked.",
      "translation_ko": "어제 갑자기 큰 비가 내렸는데 우산을 안 가져와서 온몸이 다 젖었어요."
    },
    {
      "text": "我的電腦壞掉了，結果今天的工作都做不完。",
      "pinyin": "Wǒ de diànnǎo huài diào le, jiéguǒ jīntiān de gōngzuò dōu zuò bù wán.",
      "pinyin_numeric": "wo3 de5 dian4nao3 huai4 diao4 le5, jie2guo3 jin1tian1 de5 gong1zuo4 dou1 zuo4 bu4 wan2.",
      "translation_en": "My computer broke, so I couldn't finish today's work.",
      "translation_ko": "제 컴퓨터가 고장 나서 오늘 일을 다 끝낼 수 없었어요."
    },
    {
      "text": "他因為感冒，所以今天沒有來上課。",
      "pinyin": "Tā yīnwèi gǎnmào, suǒyǐ jīntiān méiyǒu lái shàngkè.",
      "pinyin_numeric": "ta1 yin1wei4 gan3mao4, suo3yi3 jin1tian1 mei2you3 lai2 shang4ke4.",
      "translation_en": "He didn't come to class today because he has a cold.",
      "translation_ko": "그는 감기에 걸려서 오늘 수업에 오지 않았어요."
    },
    {
      "text": "我弄丟了悠遊卡，結果要重新買一張。",
      "pinyin": "Wǒ nòngdiū le yōuyóukǎ, jiéguǒ yào chóngxīn mǎi yī zhāng.",
      "pinyin_numeric": "wo3 nong4diu1 le5 you1you2ka3, jie2guo3 yao4 chong2xin1 mai3 yi1 zhang1.",
      "translation_en": "I lost my EasyCard, so I had to buy a new one.",
      "translation_ko": "유유카드를 잃어버려서 새로 한 장 사야 했어요."
    },
    {
      "text": "昨天颱風來了，所以很多商店都沒有開。",
      "pinyin": "Zuótiān táifēng lái le, suǒyǐ hěnduō shāngdiàn dōu méiyǒu kāi.",
      "pinyin_numeric": "zuo2tian1 tai2feng1 lai2 le5, suo3yi3 hen3duo1 shang1dian4 dou1 mei2you3 kai1.",
      "translation_en": "A typhoon came yesterday, so many shops were closed.",
      "translation_ko": "어제 태풍이 와서 많은 가게들이 문을 열지 않았어요."
    },
    {
      "text": "他因為頭痛，所以先回家休息了。",
      "pinyin": "Tā yīnwèi tóutòng, suǒyǐ xiān huí jiā xiūxí le.",
      "pinyin_numeric": "ta1 yin1wei4 tou2tong4, suo3yi3 xian1 hui2 jia1 xiu1xi2 le5.",
      "translation_en": "He had a headache, so he went home to rest first.",
      "translation_ko": "그는 두통 때문에 먼저 집에 가서 쉬었어요."
    },
    {
      "text": "我忘記帶錢包，結果不能買午餐。",
      "pinyin": "Wǒ wàngjì dài qiánbāo, jiéguǒ bùnéng mǎi wǔcān.",
      "pinyin_numeric": "wo3 wang4ji4 dai4 qian2bao1, jie2guo3 bu4neng2 mai3 wu3can1.",
      "translation_en": "I forgot to bring my wallet, so I couldn't buy lunch.",
      "translation_ko": "지갑을 가져오는 걸 잊어버려서 점심을 살 수 없었어요."
    }
  ]
}
